    dificil: {
      titulo: "Trigonometría Avanzada",
      contenido: [
        { tipo: "intro", texto: "La trigonometría avanzada maneja ángulos fuera del primer cuadrante, identidades complejas y ecuaciones trigonométricas." },
        { tipo: "concepto", titulo: "Cuadrantes de la circunferencia", texto: "Los ángulos se miden desde el eje positivo en sentido antihorario. Cada cuadrante tiene signos diferentes para sen, cos y tan.", subItems: ["1er cuadrante (0°-90°): todos positivos", "2do cuadrante (90°-180°): solo sen positivo", "3er cuadrante (180°-270°): solo tan positivo", "4to cuadrante (270°-360°): solo cos positivo"] },
        { tipo: "formula", formula: "sen(180° - x) = sen(x)\ncos(180° - x) = -cos(x)", descripcion: "Para ángulos en el segundo cuadrante: sen se mantiene, cos cambia de signo." },
        { tipo: "ejemplo", titulo: "Ángulo en 2do cuadrante", texto: "Calcular sen(150°):", pasos: ["150° = 180° - 30°", "sen(150°) = sen(180° - 30°) = sen(30°)", "sen(150°) = 1/2", "En el 2do cuadrante, sen es positivo ✓"] },
        { tipo: "concepto", titulo: "Ángulos negativos y mayores", texto: "Para ángulos negativos y mayores a 360°, usamos equivalencias.", subItems: ["sen(-x) = -sen(x) (奇)", "cos(-x) = cos(x) (偶)", "Para >360°: resta 360° repetidamente"] },
        { tipo: "ejemplo", titulo: "Ecuación trigonométrica", texto: "Resuelve: 2sen(x) = 1, con 0° ≤ x ≤ 180°", pasos: ["sen(x) = 1/2 = 0.5", "x = 30° (1er cuadrante)", "x = 150° (2do cuadrante: 180°-30°)", "Soluciones: x = 30° y x = 150°"] },
        { tipo: "ejemplo", titulo: "Verificación con Pitágoras", texto: "Triángulo con lados 7, 24 y 25:", pasos: ["Verificamos: 7² + 24² = 49 + 576 = 625", "25² = 625 ✓ → es rectángulo", "sen(θ) = 7/25 = 0.28", "θ = arcsen(0.28) ≈ 16.26°"] },
        { tipo: "tabla", titulo: "Signos por cuadrante (ASTC)", fila: [["1er (0-90°)", "A: Todos (+)"], ["2do (90-180°)", "S: Solo sen (+)"], ["3er (180-270°)", "T: Solo tan (+)"], ["4to (270-360°)", "C: Solo cos (+)"]] },
        { tipo: "resumen", items: ["ASTC: All-Sin-Tan-Cos por cuadrante", "sen(180°-x)=sen(x), cos(180°-x)=-cos(x)", "sen(-x)=-sen(x), cos(-x)=cos(x)", "Ecuaciones trigonométricas pueden tener múltiples soluciones", "Siempre verificar con la identidad pitagórica"] },
        { tipo: "tip", texto: "Consejo: Dibuja la circunferencia trigonométrica y marca los cuadrantes con ASTC. Es la mejor referencia para no perder el signo." },
      ],
    },
