    medio: {
      titulo: "Pidiendo Direcciones y Comida",
      contenido: [
        { tipo: "intro", texto: "Perderse en una ciudad nueva o comer en un restaurante extranjero son experiencias comunes al viajar. En esta lección aprenderás a pedir direcciones y a ordenar comida en inglés." },
        { tipo: "concepto", titulo: "Frases para pedir direcciones", texto: "Estas son las formas más comunes de preguntar dónde está algo.", subItems: ["Excuse me, where is...? = Disculpe, ¿dónde está...?", "How do I get to...? = ¿Cómo llego a...?", "Is there a ... near here? = ¿Hay un... cerca de aquí?", "Can you show me on the map? = ¿Puede mostrarme en el mapa?"] },
        { tipo: "imagen", label: "Agregar imagen de persona pidiendo direcciones", caption: "Turista pidiendo direcciones en la calle" },
        { tipo: "concepto", titulo: "Preposiciones de dirección", texto: "Estas palabras son clave para entender y dar direcciones.", subItems: ["Straight ahead = Todo recto", "Turn left = Gira a la izquierda", "Turn right = Gira a la derecha", "On the corner = En la esquina", "Across from = Frente a", "Next to = Al lado de", "Between...and = Entre...y"] },
        { tipo: "ejemplo", titulo: "Diálogo pidiendo direcciones", texto: "Una conversación típica en la calle:", pasos: ["Tourist: Excuse me, where is the train station?", "Local: Go straight for two blocks, then turn left.", "Tourist: Is it far from here?", "Local: No, it's about 5 minutes walking.", "Tourist: Thank you very much!", "Local: You're welcome! Have a nice day."] },
        { tipo: "ejemplo", titulo: "Dando direcciones detalladas", texto: "Cómo explicar dónde está un lugar:", pasos: ["Go straight on this street. (Sigue recto por esta calle.)", "Turn right at the traffic light. (Gira a la derecha en el semáforo.)", "It's next to the bank. (Está al lado del banco.)", "You can't miss it. (No puedes perdértelo.)"] },
        { tipo: "concepto", titulo: "Vocabulario del restaurante", texto: "Palabras clave que encontrarás en cualquier restaurante.", subItems: ["Menu = Menú", "Appetizer/Starter = Entrada", "Main course/Entrée = Plato principal", "Dessert = Postre", "Beverage/Drink = Bebida", "Bill/Check = Cuenta"] },
        { tipo: "imagen", label: "Agregar imagen de menú de restaurante en inglés", caption: "Ejemplo de menú con vocabulario en inglés" },
        { tipo: "ejemplo", titulo: "Diálogo en el restaurante", texto: "Una conversación completa:", pasos: ["Waiter: Good evening! A table for two?", "Customer: Yes, please.", "Waiter: Here are the menus. Are you ready to order?", "Customer: I would like the grilled chicken, please.", "Waiter: And to drink?", "Customer: Can I have a glass of water, please?", "Waiter: Would you like dessert?", "Customer: No, thank you. Can we have the bill, please?"] },
        { tipo: "tabla", titulo: "Frases útiles", fila: [["Situación", "En inglés", "En español"], ["Turn left/right", "Gira a la izquierda/derecha", "Direcciones"], ["Where is...?", "¿Dónde está...?", "Preguntar ubicación"], ["I'll have the...", "Voy a tomar el...", "Ordenar comida"], ["Check, please", "La cuenta, por favor", "Pagar"]] },
        { tipo: "resumen", items: ["Direcciones: Where is...? / Go straight / Turn left/right", "Ubicación: next to, across from, between", "Restaurante: I would like... / Can I have...?", "Cuenta: Can we have the bill/check?", "Siempre agradecer: Thank you very much!"] },
        { tipo: "tip", texto: "Consejo: 'I would like...' es más educado que 'I want...'. En restaurantes y tiendas, siempre usa 'I would like' o 'Can I have' para sonar más cortés." },
      ],
    },
    dificil: {
      titulo: "Diálogo de Compras en una Tienda",
      contenido: [
        { tipo: "intro", texto: "Hacer compras en inglés requiere vocabulario específico: preguntar por precios, tallas, colores, y negociar. Esta lección te prepara para cualquier situación de compra." },
        { tipo: "concepto", titulo: "Frases para iniciar la compra", texto: "Cuando entras a una tienda, el vendedor te saludará con estas frases.", subItems: ["Can I help you? = ¿Puedo ayudarle?", "Are you looking for something? = ¿Busca algo?", "Just looking, thanks. = Solo mirando, gracias.", "I'm looking for... = Estoy buscando...", "Where are the...? = ¿Dónde están los/las...?"] },
        { tipo: "imagen", label: "Agregar imagen de compras en tienda en inglés", caption: "Cliente y vendedor en una tienda de ropa" },
        { tipo: "concepto", titulo: "Preguntar por precios y tallas", texto: "Frases esenciales para encontrar lo que necesitas.", subItems: ["How much is this? = ¿Cuánto cuesta esto?", "How much are these? = ¿Cuánto cuestan estos?", "Do you have this in a bigger size? = ¿Lo tiene en talla más grande?", "Do you have this in blue? = ¿Lo tiene en azul?", "Is there a discount? = ¿Hay descuento?"] },
        { tipo: "ejemplo", titulo: "Diálogo comprando ropa", texto: "Una conversación completa en una tienda de ropa:", pasos: ["Clerk: Hi! Can I help you?", "Customer: Yes, I'm looking for a jacket.", "Clerk: What size do you wear?", "Customer: Medium, please.", "Clerk: Here you go. The fitting room is over there.", "Customer: How much is it?", "Clerk: It's $45, but there's a 20% discount today.", "Customer: Great! I'll take it."] },
        { tipo: "concepto", titulo: "Pagar y hacer devoluciones", texto: "Frases para el momento de pagar o si necesitas devolver algo.", subItems: ["I'll take this one. = Me llevo este.", "Can I pay by card? = ¿Puedo pagar con tarjeta?", "Do you accept cash? = ¿Aceptan efectivo?", "I'd like to return this. = Quiero devolver esto.", "Do you have the receipt? = ¿Tiene el recibo?"] },
        { tipo: "ejemplo", titulo: "En una tienda de souvenirs", texto: "Comprando recuerdos de viaje:", pasos: ["Tourist: How much is this keychain?", "Seller: It's five dollars.", "Tourist: Can you give me a discount if I buy three?", "Seller: Sure! Three for twelve dollars.", "Tourist: Perfect! I'll take them.", "Seller: Cash or card?", "Tourist: Card, please. Here you go.", "Seller: Here's your receipt. Thank you!"] },
        { tipo: "tabla", titulo: "Frases de compras", fila: [["Situación", "En inglés", "Significado"], ["¿Cuánto cuesta?", "How much is it?", "Precio"], ["Talla", "What size?", "¿Qué talla?"], ["Descuento", "Is there a discount?", "¿Hay rebaja?"], ["Pagar", "Can I pay by card?", "¿Tarjeta?"], ["Devolver", "I'd like to return this", "Quiero devolver"], ["Llevar", "I'll take it", "Me lo llevo"]] },
        { tipo: "resumen", items: ["Entrada: Can I help you? / I'm looking for...", "Precio: How much is...?", "Talla: Do you have this in (medium/large)?", "Compra: I'll take this one.", "Pago: Cash or card? / Can I pay by card?"] },
        { tipo: "tip", texto: "Consejo: En países angloparlantes los precios NO se negocian (excepto en mercados). En tiendas oficiales, el precio que ves es el que pagas." },
      ],
    },
